namespace NotificationsApp.Services;

public record NotificationItem(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly object _lock = new();

    private readonly List<NotificationItem> _notifications = [];

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(
        [
            new(NextId(), "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)),
            new(NextId(), "Your profile was updated.", DateTime.UtcNow.AddMinutes(-15)),
            new(NextId(), "New comment on your post.", DateTime.UtcNow.AddMinutes(-5)),
        ]);
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int sinceId)
    {
        lock (_lock)
        {
            var newer = _notifications.Where(n => n.Id > sinceId).ToList();

            // Simulate occasional new notifications arriving
            if (Random.Shared.Next(0, 3) == 0)
            {
                var fresh = new NotificationItem(
                    NextId(),
                    $"New event at {DateTime.UtcNow:T}",
                    DateTime.UtcNow);
                _notifications.Add(fresh);
                newer.Add(fresh);
            }

            return Task.FromResult(newer);
        }
    }

    private int NextId() => _nextId++;
}

@page "/notifications"
@rendermode InteractiveServer
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationItem> notifications = [];
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? PersistedNotifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (PersistedNotifications is not null)
        {
            // Interactive render: state was restored from prerender — skip the fetch.
            notifications = PersistedNotifications;
        }
        else
        {
            // Prerender: load initial data so it appears in the static HTML.
            notifications = await NotificationService.GetNotificationsAsync();
            PersistedNotifications = notifications;
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only runs after the interactive runtime attaches — never during prerender.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            var sinceId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
            var newer = await NotificationService.GetNotificationsSinceAsync(sinceId);

            if (newer.Count > 0)
            {
                await InvokeAsync(() =>
                {
                    notifications.AddRange(newer);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

